'use client';

import { useUIStore, type AppTab } from '@/stores/ui-store';
import { useProfileStore } from '@/stores/profile-store';
import { useClaimStore } from '@/stores/claim-store';
import {
  LayoutDashboard,
  FileText,
  ScanSearch,
  ClipboardList,
  MapPin,
  Calculator,
  Printer,
  Camera,
  Receipt,
  RotateCcw,
  User,
  Brain,
  Plus,
  FolderOpen,
  ChevronLeft,
  ChevronRight,
  Menu,
  Wifi,
  WifiOff,
  Cloud,
} from 'lucide-react';

interface NavItem {
  id: AppTab;
  label: string;
  icon: React.ReactNode;
  group: 'main' | 'claim' | 'output' | 'settings';
  requiresClaim?: boolean;
}

const NAV_ITEMS: NavItem[] = [
  // ─── Main ──────────────────────────────────────────
  { id: 'dashboard', label: 'Dashboard', icon: <LayoutDashboard size={18} />, group: 'main' },

  // ─── Claim Workflow ────────────────────────────────
  { id: 'documents', label: 'Documents', icon: <FileText size={18} />, group: 'claim', requiresClaim: true },
  { id: 'review', label: 'AI Review', icon: <ScanSearch size={18} />, group: 'claim', requiresClaim: true },
  { id: 'details', label: 'Claim Details', icon: <ClipboardList size={18} />, group: 'claim', requiresClaim: true },
  { id: 'spot', label: 'Spot Survey', icon: <MapPin size={18} />, group: 'claim', requiresClaim: true },
  { id: 'assessment', label: 'Assessment', icon: <Calculator size={18} />, group: 'claim', requiresClaim: true },

  // ─── Output ────────────────────────────────────────
  { id: 'reports', label: 'Reports', icon: <Printer size={18} />, group: 'output', requiresClaim: true },
  { id: 'photos', label: 'Photo Sheet', icon: <Camera size={18} />, group: 'output', requiresClaim: true },
  { id: 'fees', label: 'Fee Bill', icon: <Receipt size={18} />, group: 'output', requiresClaim: true },
  { id: 'reinspection', label: 'Reinspection', icon: <RotateCcw size={18} />, group: 'output', requiresClaim: true },

  // ─── Settings ──────────────────────────────────────
  { id: 'profile', label: 'Profile', icon: <User size={18} />, group: 'settings' },
  { id: 'learning', label: 'Learning', icon: <Brain size={18} />, group: 'settings' },
];

const GROUP_LABELS: Record<string, string> = {
  main: '',
  claim: 'CLAIM WORKFLOW',
  output: 'OUTPUT',
  settings: 'SETTINGS',
};

import { useState, useEffect } from 'react';

export function Sidebar() {
  const [mounted, setMounted] = useState(false);
  const { activeTab, setActiveTab, sidebarCollapsed, toggleSidebar, isOnline, isDriveConnected, driveEmail } = useUIStore();
  const { setNewClaimDialogOpen, setClaimsListOpen } = useUIStore();
  const { getInitials, profile } = useProfileStore();
  const { currentClaim } = useClaimStore();

  useEffect(() => {
    setMounted(true);
  }, []);

  const hasClaim = !!currentClaim;

  const groups = ['main', 'claim', 'output', 'settings'] as const;

  return (
    <>
      {/* Mobile overlay */}
      <div
        className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm lg:hidden"
        style={{ display: useUIStore.getState().sidebarMobileOpen ? 'block' : 'none' }}
        onClick={() => useUIStore.getState().setSidebarMobileOpen(false)}
      />

      <aside
        className={`
          fixed top-0 left-0 z-50 h-full flex flex-col
          bg-sidebar border-r border-sidebar-border
          transition-all duration-300 ease-in-out
          ${sidebarCollapsed ? 'w-[60px]' : 'w-[240px]'}
          lg:relative
        `}
      >
        {/* ─── Header ──────────────────────────────────── */}
        <div className="flex items-center gap-3 px-3 py-4 border-b border-sidebar-border">
          <div className="flex-shrink-0 w-8 h-8 rounded-lg bg-primary flex items-center justify-center text-primary-foreground text-xs font-bold">
            {getInitials()}
          </div>
          {!sidebarCollapsed && (
            <div className="flex-1 min-w-0">
              <div className="text-sm font-semibold text-sidebar-foreground truncate">
                {profile.name || 'Surveyor'}
              </div>
              <div className="text-[10px] text-muted-foreground truncate">
                {profile.licenceNumber || 'License #'}
              </div>
            </div>
          )}
          <button
            onClick={toggleSidebar}
            className="hidden lg:flex items-center justify-center w-6 h-6 rounded-md hover:bg-sidebar-accent text-muted-foreground"
          >
            {sidebarCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
          </button>
        </div>

        {/* ─── Quick Actions ───────────────────────────── */}
        <div className={`flex gap-2 px-3 py-3 border-b border-sidebar-border ${sidebarCollapsed ? 'flex-col items-center' : ''}`}>
          <button
            onClick={() => setNewClaimDialogOpen(true)}
            className="flex items-center gap-2 px-3 py-2 rounded-lg bg-primary hover:bg-primary/90 text-primary-foreground text-xs font-semibold flex-1 justify-center"
            title="New Claim"
          >
            <Plus size={14} />
            {!sidebarCollapsed && 'New Claim'}
          </button>
          {!sidebarCollapsed && (
            <button
              onClick={() => setClaimsListOpen(true)}
              className="flex items-center justify-center w-9 h-9 rounded-lg border border-sidebar-border hover:bg-sidebar-accent text-muted-foreground"
              title="Open Claim"
            >
              <FolderOpen size={14} />
            </button>
          )}
        </div>

        {/* ─── Claim Badge ─────────────────────────────── */}
        {hasClaim && !sidebarCollapsed && (
          <div className="mx-3 mt-3 px-3 py-2 rounded-lg bg-primary/10 border border-primary/20">
            <div className="text-[10px] font-semibold text-primary uppercase tracking-wider">
              {currentClaim.surveyType} Survey
            </div>
            <div className="text-xs font-bold text-sidebar-foreground truncate mt-0.5">
              {currentClaim.vehicle.registrationNumber || currentClaim.reportNo || 'New Claim'}
            </div>
          </div>
        )}

        {/* ─── Navigation ──────────────────────────────── */}
        <nav className="flex-1 overflow-y-auto py-2 px-2">
          {groups.map((group) => {
            const items = NAV_ITEMS.filter((item) => item.group === group);
            if (!items.length) return null;

            return (
              <div key={group} className="mb-2">
                {GROUP_LABELS[group] && !sidebarCollapsed && (
                  <div className="px-2 py-2 text-[9px] font-bold text-muted-foreground/60 uppercase tracking-[0.15em]">
                    {GROUP_LABELS[group]}
                  </div>
                )}
                {items.map((item) => {
                  const disabled = item.requiresClaim && !hasClaim;
                  const isActive = activeTab === item.id;

                  return (
                    <button
                      key={item.id}
                      onClick={() => !disabled && setActiveTab(item.id)}
                      disabled={disabled}
                      title={sidebarCollapsed ? item.label : undefined}
                      className={`
                        w-full flex items-center gap-3 px-2.5 py-2 rounded-lg text-sm
                        transition-all duration-150 mb-0.5
                        ${sidebarCollapsed ? 'justify-center' : ''}
                        ${isActive
                          ? 'bg-sidebar-accent text-sidebar-primary font-semibold'
                          : disabled
                            ? 'text-muted-foreground/30 cursor-not-allowed'
                            : 'text-sidebar-foreground hover:bg-sidebar-accent hover:text-sidebar-accent-foreground'
                        }
                      `}
                    >
                      <span className={isActive ? 'text-sidebar-primary' : ''}>{item.icon}</span>
                      {!sidebarCollapsed && <span className="truncate">{item.label}</span>}
                    </button>
                  );
                })}
              </div>
            );
          })}
        </nav>

        {/* ─── Status Bar ──────────────────────────────── */}
        <div className="px-3 py-3 border-t border-sidebar-border space-y-1.5 h-[68px]">
          {mounted && (!sidebarCollapsed ? (
            <>
              <div className={`flex items-center gap-2 text-[10px] ${isOnline ? 'text-success' : 'text-danger'}`}>
                {isOnline ? <Wifi size={12} /> : <WifiOff size={12} />}
                {isOnline ? 'Online' : 'Offline — data saved locally'}
              </div>
              <div className={`flex items-center gap-2 text-[10px] ${isDriveConnected ? 'text-primary' : 'text-muted-foreground'}`}>
                <Cloud size={12} />
                {isDriveConnected ? driveEmail : 'Drive: Not connected'}
              </div>
            </>
          ) : (
            <div className="flex flex-col items-center gap-2">
              {isOnline ? <Wifi size={12} className="text-success" /> : <WifiOff size={12} className="text-danger" />}
              <Cloud size={12} className={isDriveConnected ? 'text-primary' : 'text-muted-foreground'} />
            </div>
          ))}
        </div>
      </aside>
    </>
  );
}

export function MobileMenuButton() {
  return (
    <button
      className="lg:hidden fixed top-3 left-3 z-50 p-2 rounded-lg bg-card border border-border"
      onClick={() => useUIStore.getState().setSidebarMobileOpen(true)}
    >
      <Menu size={20} />
    </button>
  );
}
