'use client';

import { Sidebar, MobileMenuButton } from '@/components/layout/sidebar';
import { useUIStore } from '@/stores/ui-store';
import { useClaimStore } from '@/stores/claim-store';
import {
  LayoutDashboard,
  Plus,
  Clock,
  TrendingUp,
  FileCheck,
  Zap,
} from 'lucide-react';

// ─── Dashboard Tab Content ──────────────────────────────
function DashboardContent() {
  const { setNewClaimDialogOpen } = useUIStore();
  const { claimsList } = useClaimStore();

  return (
    <div className="p-6 lg:p-8 max-w-6xl mx-auto">
      {/* Hero */}
      <div className="mb-8">
        <h1 className="text-2xl lg:text-3xl font-bold text-foreground tracking-tight">
          SurveyOS <span className="text-primary">V2</span>
        </h1>
        <p className="text-muted-foreground text-sm mt-1">
          Motor Insurance Survey Platform — AI-Powered, Offline-First
        </p>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 mb-8">
        <button
          onClick={() => setNewClaimDialogOpen(true)}
          className="group flex items-center gap-4 p-5 rounded-xl bg-primary/10 border border-primary/20 hover:bg-primary/15 hover:border-primary/30 transition-all"
        >
          <div className="w-11 h-11 rounded-lg bg-primary flex items-center justify-center text-primary-foreground">
            <Plus size={22} />
          </div>
          <div className="text-left">
            <div className="text-sm font-semibold text-foreground">New Claim</div>
            <div className="text-xs text-muted-foreground">Start a survey</div>
          </div>
        </button>

        <button className="group flex items-center gap-4 p-5 rounded-xl bg-card border border-border hover:border-primary/30 transition-all">
          <div className="w-11 h-11 rounded-lg bg-secondary flex items-center justify-center text-secondary-foreground">
            <FileCheck size={22} />
          </div>
          <div className="text-left">
            <div className="text-sm font-semibold text-foreground">Open Claim</div>
            <div className="text-xs text-muted-foreground">{claimsList.length} saved</div>
          </div>
        </button>

        <button className="group flex items-center gap-4 p-5 rounded-xl bg-card border border-border hover:border-primary/30 transition-all">
          <div className="w-11 h-11 rounded-lg bg-secondary flex items-center justify-center text-secondary-foreground">
            <Zap size={22} />
          </div>
          <div className="text-left">
            <div className="text-sm font-semibold text-foreground">Quick Extract</div>
            <div className="text-xs text-muted-foreground">AI document scan</div>
          </div>
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {[
          { label: 'Claims Today', value: '0', icon: <LayoutDashboard size={16} />, color: 'text-primary' },
          { label: 'This Week', value: '0', icon: <TrendingUp size={16} />, color: 'text-success' },
          { label: 'Pending', value: '0', icon: <Clock size={16} />, color: 'text-amber' },
          { label: 'Total Claims', value: String(claimsList.length), icon: <FileCheck size={16} />, color: 'text-muted-foreground' },
        ].map((stat) => (
          <div key={stat.label} className="p-4 rounded-xl bg-card border border-border">
            <div className="flex items-center gap-2 mb-2">
              <span className={stat.color}>{stat.icon}</span>
              <span className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">{stat.label}</span>
            </div>
            <div className="text-2xl font-bold text-foreground">{stat.value}</div>
          </div>
        ))}
      </div>

      {/* Recent Claims */}
      <div className="rounded-xl bg-card border border-border overflow-hidden">
        <div className="px-5 py-4 border-b border-border flex items-center justify-between">
          <h2 className="text-sm font-semibold text-foreground">Recent Claims</h2>
          <span className="text-[10px] text-muted-foreground">{claimsList.length} total</span>
        </div>
        {claimsList.length === 0 ? (
          <div className="p-8 text-center">
            <div className="text-muted-foreground/40 text-4xl mb-3">📋</div>
            <div className="text-sm text-muted-foreground">No claims yet</div>
            <div className="text-xs text-muted-foreground/60 mt-1">
              Click &quot;New Claim&quot; to start your first survey
            </div>
          </div>
        ) : (
          <div className="divide-y divide-border">
            {claimsList.slice(0, 10).map((claim) => (
              <div
                key={claim.id}
                className="px-5 py-3 hover:bg-accent/50 cursor-pointer transition-colors flex items-center justify-between"
              >
                <div>
                  <div className="text-sm font-medium text-foreground">{claim.label || 'Untitled Claim'}</div>
                  <div className="text-[10px] text-muted-foreground">
                    {claim.surveyType.toUpperCase()} • {new Date(claim.updatedAt).toLocaleDateString()}
                  </div>
                </div>
                <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full ${
                  claim.surveyType === 'spot' ? 'bg-amber-soft text-amber' :
                  claim.surveyType === 'final' ? 'bg-teal-soft text-teal' :
                  'bg-secondary text-secondary-foreground'
                }`}>
                  {claim.surveyType.toUpperCase()}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { DetailsTab } from '@/components/tabs/DetailsTab';
import { AssessmentTab } from '@/components/tabs/AssessmentTab';
import { useAutoSave } from '@/hooks/useAutoSave';
import { NewClaimDialog } from '@/components/dialogs/NewClaimDialog';

// ─── Placeholder for other tabs ─────────────────────────
function TabPlaceholder({ tab }: { tab: string }) {
  if (tab === 'details') return <DetailsTab />;
  if (tab === 'assessment') return <AssessmentTab />;

  return (
    <div className="flex flex-col items-center justify-center h-full min-h-[60vh]">
      <div className="text-center">
        <div className="text-4xl mb-3 opacity-30">🚧</div>
        <div className="text-lg font-semibold text-foreground capitalize">{tab}</div>
        <div className="text-sm text-muted-foreground mt-1">Coming in Phase 4</div>
      </div>
    </div>
  );
}

// ─── Main Page ──────────────────────────────────────────
export default function Home() {
  const { activeTab } = useUIStore();
  
  // Enable offline-first sync (1000ms debounce on keystrokes)
  useAutoSave(1000);

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar />
      <MobileMenuButton />

      <main className="flex-1 overflow-y-auto bg-background">
        {activeTab === 'dashboard' ? <DashboardContent /> : <TabPlaceholder tab={activeTab} />}
      </main>

      {/* Global Modals */}
      <NewClaimDialog />
    </div>
  );
}
