'use client';

import { useClaimStore } from '@/stores/claim-store';
import { computeAssessmentSummary, formatCurrency } from '@/lib/calculations';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Separator } from '@/components/ui/separator';

export function AssessmentSummary() {
  const { currentClaim, updateFeeBill } = useClaimStore();

  if (!currentClaim) return null;

  // Real-time zero-state math execution
  const summary = computeAssessmentSummary(currentClaim);
  const fb = currentClaim.feeBill;

  return (
    <Card className="border-border shadow-lg sticky top-6">
      <CardHeader className="bg-primary/5 border-b border-border pb-4">
        <CardTitle className="text-lg text-primary">Financial Summary</CardTitle>
      </CardHeader>
      
      <CardContent className="p-0">
        <div className="p-5 space-y-4">
          <div className="flex justify-between items-center text-sm">
            <span className="text-muted-foreground">Total Parts Assessed</span>
            <span className="font-semibold">{formatCurrency(summary.totalPartsAssessed)}</span>
          </div>
          <div className="flex justify-between items-center text-sm text-danger">
            <span>Parts Depreciation</span>
            <span className="font-semibold">- {formatCurrency(summary.totalPartsDepreciation)}</span>
          </div>
          <Separator />
          
          <div className="flex justify-between items-center text-sm">
            <span className="text-muted-foreground">Total Labour Assessed</span>
            <span className="font-semibold">{formatCurrency(summary.totalLabourAssessed)}</span>
          </div>
          
          <div className="flex justify-between items-center text-sm text-amber">
            <span>Painting Material Dep (@25%)</span>
            <span className="font-semibold">- {formatCurrency(summary.totalPaintMaterialDepreciation)}</span>
          </div>
          
          <Separator />
          
          <div className="flex justify-between items-center text-sm font-semibold text-foreground">
            <span>Net Assessment before GST</span>
            <span>{formatCurrency(summary.netAssessmentBeforeTaxes)}</span>
          </div>
          
          <div className="flex justify-between items-center text-sm">
            <span className="text-muted-foreground">Total GST Additions</span>
            <span className="font-semibold">{formatCurrency(summary.totalGSTAmount)}</span>
          </div>
          <div className="flex justify-between items-center text-sm text-sky-500">
            <span>Total IMT-23 Deductions</span>
            <span className="font-semibold">- {formatCurrency(summary.totalIMT23Deduction)}</span>
          </div>
        </div>

        <div className="bg-muted/30 p-5 border-y border-border space-y-4">
          <div className="space-y-2">
            <div className="flex justify-between items-center">
              <Label htmlFor="salvage-value" className="text-xs text-muted-foreground uppercase tracking-wider">Salvage Value (₹)</Label>
            </div>
            <Input
              id="salvage-value"
              type="number"
              value={fb.salvageValue || ''}
              onChange={(e) => updateFeeBill({ salvageValue: parseFloat(e.target.value) || 0 })}
              className="text-right font-bold text-danger bg-background focus:ring-danger"
              placeholder="0.00"
              min="0"
            />
          </div>
          
          <div className="space-y-2">
            <div className="flex justify-between items-center">
              <Label htmlFor="policy-excess" className="text-xs text-muted-foreground uppercase tracking-wider">Policy Excess (₹)</Label>
            </div>
            <Input
              id="policy-excess"
              type="number"
              value={fb.lessExcess || ''}
              onChange={(e) => updateFeeBill({ lessExcess: parseFloat(e.target.value) || 0 })}
              className="text-right font-bold text-danger bg-background focus:ring-danger"
              placeholder="1000.00"
              min="0"
            />
          </div>
        </div>

        <div className="p-6 bg-card rounded-b-xl border-t-2 border-primary">
          <div className="flex justify-between items-end">
            <div>
              <div className="text-xs font-bold text-primary uppercase tracking-widest mb-1">Total Liability</div>
              <div className="text-[10px] text-muted-foreground">Net Payable to Insured</div>
            </div>
            <div className="text-3xl font-black text-foreground tracking-tight tabular-nums">
              {formatCurrency(summary.netLiability)}
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}
