import { useEffect, useRef } from 'react';
import { useClaimStore } from '@/stores/claim-store';
import { saveClaim } from '@/lib/storage/indexeddb';

/**
 * A hook that listens to changes in the current claim and automatically
 * saves them to IndexedDB after a debounce period (default 1000ms).
 */
export function useAutoSave(debounceMs = 1000) {
  const { currentClaim, isDirty, markClean } = useClaimStore();
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const lastSavedUpdateRef = useRef<string | null>(null);

  useEffect(() => {
    // If we have no claim or it isn't marked dirty, do nothing
    if (!currentClaim || !isDirty) return;

    // Avoid saving if the timestamp hasn't actually changed since last save
    if (lastSavedUpdateRef.current === currentClaim.updatedAt) return;

    // Clear previous timer
    if (timerRef.current) clearTimeout(timerRef.current);

    // Set new timer for debounce
    timerRef.current = setTimeout(async () => {
      try {
        await saveClaim(currentClaim);
        lastSavedUpdateRef.current = currentClaim.updatedAt;
        markClean();
        console.log(`[AutoSave] Claim ${currentClaim.id} saved to IndexedDB`);
      } catch (err) {
        console.error('[AutoSave] Failed to save claim:', err);
      }
    }, debounceMs);

    // Cleanup timer on unmount
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [currentClaim, isDirty, debounceMs, markClean]);
}
